from typing import Sequence, List

def moving_max(nums: Sequence[float], k: int) -> List[float]:
    """Return a list of maximums for each contiguous window of length k in nums."""
    n = len(nums)
    if k < 1 or k > n:
        raise ValueError("k must be between 1 and the length of nums")

    result: List[float] = []
    dq: deque[int] = deque()

    for i, num in enumerate(nums):
        if dq and dq[0] == i - k:
            dq.popleft()

        while dq and nums[dq[-1]] <= num:
            dq.pop()

        dq.append(i)

        if i >= k - 1:
            result.append(nums[dq[0]])

    return result
