def parse_csv_row(line: str) -> list[str]:
    """Parse a single RFC 4180 CSV row into a list of field strings.

    Raises ValueError on malformed input, including unquoted double quotes,
    unterminated quoted fields, or invalid characters following a closing quote.
    """
    if not isinstance(line, str):
        raise TypeError("line must be a string")

    fields: list[str] = []
    current_field: list[str] = []
    in_quotes: bool = False
    i: int = 0
    n: int = len(line)

    while i < n:
        char = line[i]

        if in_quotes:
            if char == '"':
                if i + 1 < n and line[i+1] == '"':
                    current_field.append('"')
                    i += 2
                else:
                    in_quotes = False
                    if i + 1 < n and line[i+1] != ',':
                        raise ValueError("Invalid character after closing quote")
                    i += 1
            else:
                current_field.append(char)
                i += 1
        else:
            if char == '"':
                if current_field:
                    raise ValueError("Double quote in unquoted field")
                in_quotes = True
                i += 1
            elif char == ',':
                fields.append(''.join(current_field))
                current_field = []
                i += 1
            else:
                current_field.append(char)
                i += 1

    if in_quotes:
        raise ValueError("Unterminated quoted field")

    fields.append(''.join(current_field))
    return fields
