import heapq
from typing import Any, Dict, List, Tuple

def dijkstra(graph: Dict[Any, List[Tuple[Any, float]]], start: Any, end: Any) -> float:
    """Compute the shortest-path distance between two nodes in a weighted graph.

    Args:
        graph: Mapping of each node to a list of (neighbor, weight) pairs.
        start: The source node.
        end: The destination node.

    Returns:
        The shortest distance from start to end, 0 if they are the same,
        or float('inf') if end is unreachable.

    Raises:
        ValueError: If start or end is not a valid node in the graph,
                    or if any edge weight is negative.
    """
    all_nodes = set(graph.keys())
    for neighbors in graph.values():
        for node, weight in neighbors:
            if weight < 0:
                raise ValueError("Graph contains negative edge weights")
            all_nodes.add(node)

    if start not in all_nodes:
        raise ValueError(f"start node {start!r} is not in the graph")
    if end not in all_nodes:
        raise ValueError(f"end node {end!r} is not in the graph")

    if start == end:
        return 0.0

    distances: Dict[Any, float] = {start: 0.0}
    pq: List[Tuple[float, Any]] = [(0.0, start)]

    while pq:
        current_dist, current_node = heapq.heappop(pq)

        if current_dist > distances[current_node]:
            continue

        if current_node == end:
            return current_dist

        for neighbor, weight in graph.get(current_node, []):
            new_dist = current_dist + weight
            if neighbor not in distances or new_dist < distances[neighbor]:
                distances[neighbor] = new_dist
                heapq.heappush(pq, (new_dist, neighbor))

    return float('inf')
