    For keys present in both dicts whose values are both dicts, merge recursively.
    Otherwise, the value from `b` wins.

    Neither input nor any nested object is mutated. The returned structure shares
    no mutable objects with either input.

    Args:
        a: The base dictionary.
        b: The dictionary whose values take precedence on conflict.

    Returns:
        A new dictionary containing the merged result.

    Raises:
        TypeError: If either input is not a dict.
    """
    if not isinstance(a, dict):
        raise TypeError(f"Expected dict, got {type(a).__name__}")
    if not isinstance(b, dict):
        raise TypeError(f"Expected dict, got {type(b).__name__}")

