            result[key] = deep_copy_dict(value)
        elif isinstance(value, list):
            result[key] = deep_copy_list(value)
        else:
            # Immutable types can be shared safely
            result[key] = value

    # Merge items from b
    for key in b:
        b_value = b[key]
