            a_value = a[key]
            # If both values are dicts, merge recursively
            if isinstance(a_value, dict) and isinstance(b_value, dict):
                result[key] = deep_merge(a_value, b_value)
            else:
                # b's value wins; copy it if mutable
                if isinstance(b_value, dict):
