    if not sorted_nums:
        return ""

    ranges = []
    start = sorted_nums[0]
    end = sorted_nums[0]

    for i in range(1, len(sorted_nums)):
        if sorted_nums[i] == end + 1:
            end = sorted_nums[i]
        else:
            # Process the current range
            if end - start >= 2:
                ranges.append(f"{start}-{end}")
            else:
                for n in range(start, end + 1):
