    result = parser.parse_expression()

    if parser.pos < len(parser.tokens):
        raise ValueError(f"Unexpected token after expression: {parser.tokens[parser.pos]}")

    return float(result)


def _tokenize(expr: str) -> list[str]:
    """Tokenize the expression string into a list of tokens."""
    tokens = []
    i = 0
    n = len(expr)

    while i < n:
        c = expr[i]

        # Skip whitespace
        if c.isspace():
            i += 1
            continue

        # Numbers: integer or decimal
        if c.isdigit() or (c == '.' and i + 1 < n and expr[i + 1].isdigit()):
            j = i
            has_dot = False
            while j < n and (expr[j].isdigit() or expr[j] == '.'):
                if expr[j] == '.':
                    if has_dot:
                        raise ValueError(f"Invalid number at position {i}")
                    has_dot = True
                j += 1
            num_str = expr[i:j]
            tokens.append(num_str)
            i = j
            continue

        # Operators and parentheses
        if c in '+-*/()':
            tokens.append(c)
            i += 1
            continue

        raise ValueError(f"Invalid character at position {i}: '{c}'")

    return tokens


class _Parser:
    """Recursive descent parser for arithmetic expressions."""

    def __init__(self, tokens: list[str]):
        self.tokens = tokens
        self.pos = 0

    def peek(self) -> str | None:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self) -> str:
        token = self.peek()
        if token is None:
            raise ValueError("Unexpected end of expression")
        self.pos += 1
        return token

    def parse_expression(self) -> float:
        """Parse addition and subtraction (lowest precedence)."""
        result = self.parse_term()

        while True:
            token = self.peek()
            if token in ('+', '-'):
                self.consume()
                right = self.parse_term()
                if token == '+':
                    result += right
                else:
                    result -= right
            else:
                break

        return result

    def parse_term(self) -> float:
        """Parse multiplication and division (higher precedence)."""
        result = self.parse_unary()

        while True:
            token = self.peek()
            if token in ('*', '/'):
                self.consume()
                right = self.parse_unary()
                if token == '*':
                    result *= right
                else:
                    if right == 0.0:
                        raise ValueError("Division by zero")
                    result /= right
            else:
                break

        return result

    def parse_unary(self) -> float:
        """Parse unary + and -."""
        token = self.peek()
        if token == '-':
            self.consume()
            operand = self.parse_unary()
            return -operand
        elif token == '+':
            self.consume()
            return self.parse_unary()
        else:
            return self.parse_primary()

    def parse_primary(self) -> float:
        """Parse primary expressions: numbers and parenthesized expressions."""
        token = self.peek()

        if token is None:
            raise ValueError("Unexpected end of expression")

        # Parenthesized expression
        if token == '(':
            self.consume()  # consume '('
            result = self.parse_expression()
            close = self.peek()
            if close != ')':
                raise ValueError(f"Expected ')' but got '{close}'")
            self.consume()  # consume ')'
            return result

        # Number literal
        if token[0].isdigit() or (token.startswith('.') and len(token) > 1):
            self.consume()
            try:
                return float(token)
            except ValueError:
                raise ValueError(f"Invalid number: '{token}'")

        raise ValueError(f"Unexpected token: '{token}'")
